pragma solidity ^0.8.0;

import "@openzeppelin/contracts/security/ReentrancyGuard.sol";

contract SimpleEscrow is ReentrancyGuard {
    address public buyer;
    address public seller;
    address public arbiter;
    uint256 public balance;

    event Deposit(address indexed from, uint256 amount);
    event Release(address indexed to, uint256 amount);
    event Refund(address indexed to, uint256 amount);

    modifier onlyBuyer() {
        require(msg.sender == buyer, "Only buyer can deposit");
        _;
    }

    modifier onlyArbiter() {
        require(msg.sender == arbiter, "Only arbiter can release or refund");
        _;
    }

    constructor(address _buyer, address _seller, address _arbiter) {
        buyer = _buyer;
        seller = _seller;
        arbiter = _arbiter;
    }

    receive() external payable onlyBuyer {
        require(balance == 0, "Deposit already made");
        balance += msg.value;
        emit Deposit(msg.sender, msg.value);
    }

    function release() public onlyArbiter nonReentrant {
        require(balance > 0, "No balance to release");
        uint256 amount = balance;
        balance = 0;
        (bool success, ) = seller.call{value: amount}("");
        require(success, "Failed to send Ether");
        emit Release(seller, amount);
    }

    function refund() public onlyArbiter nonReentrant {
        require(balance > 0, "No balance to refund");
        uint256 amount = balance;
        balance = 0;
        (bool success, ) = buyer.call{value: amount}("");
        require(success, "Failed to send Ether");
        emit Refund(buyer, amount);
    }

    function getBalance() public view returns (uint256) {
        return balance;
    }

    function getBuyer() public view returns (address) {
        return buyer;
    }

    function getSeller() public view returns (address) {
        return seller;
    }

    function getArbiter() public view returns (address) {
        return arbiter;
    }
}
